solution_code:
#include <iostream>
#include <string>

void printLine(std::ostream& out, const std::string& text) {
    out << text << "\n";
}

int main() {
    std::string word;
    std::cin >> word;
    printLine(std::cout, word);
    printLine(std::cout, word);
    return 0;
}
